import math

class LocalRAGIndex:
    def __init__(self):
        self.documents = []
        self.vectors = []

    def trigrams(self, text):
        t = text.lower()
        vec = {}
        for i in range(len(t) - 2):
            tri = t[i:i+3]
            vec[tri] = vec.get(tri, 0) + 1
        return vec

    def normalize(self, vec):
        mag = math.sqrt(sum(v**2 for v in vec.values()))
        if mag == 0:
            return vec
        for k in vec:
            vec[k] /= mag
        return vec

    def add_documents(self, docs):
        for doc in docs:
            self.documents.append(doc)
            self.vectors.append(self.normalize(self.trigrams(doc)))

    def dot_product(self, vec_a, vec_b):
        return sum(vec_a.get(k, 0) * vec_b.get(k, 0) for k in vec_a)

    def search(self, query, top_k=3):
        q_text = "query: " + query
        q_vec = self.normalize(self.trigrams(q_text))
        scored = [
            {"document": doc, "score": self.dot_product(q_vec, dv)}
            for doc, dv in zip(self.documents, self.vectors)
        ]
        scored.sort(key=lambda x: x["score"], reverse=True)
        return scored[:top_k]

    def memory_report(self):
        all_keys = set()
        for v in self.vectors:
            all_keys.update(v.keys())
        return {
            "num_documents": len(self.documents),
            "num_unique_features": len(all_keys),
            "bytes_estimate": len(all_keys) * 8
        }

